1	/** A live cell's position on the infinite grid as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const neighborsOf = ([x, y]: Cell): Cell[] =>
11	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
12	
13	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
14	const keyToCell = (k: string): Cell =>
15	  k.split(",").map(Number) as [number, number];
16	
17	/**
18	 * Computes the next generation of live cells in Conway's Game of Life.
19	 *
20	 * @param cells - The currently live cells on the infinite grid.
21	 * @returns The live cells in the next generation.
22	 */
23	export function nextGeneration(cells: Cell[]): Cell[] {
24	  const liveSet = new Set(cells.map(cellKey));
25	
26	  const candidateKeys = new Set<string>(liveSet);
27	  for (const cell of cells) {
28	    for (const neighbor of neighborsOf(cell)) {
29	      candidateKeys.add(cellKey(neighbor));
30	    }
31	  }
32	
33	  const survivesOrIsBorn = (cell: Cell): boolean => {
34	    const liveNeighbors = neighborsOf(cell).filter((n) =>
35	      liveSet.has(cellKey(n)),
36	    ).length;
37	    return liveNeighbors === 3 || (liveNeighbors === 2 && liveSet.has(cellKey(cell)));
38	  };
39	
40	  return [...candidateKeys].map(keyToCell).filter(survivesOrIsBorn);
41	}
42

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty array (empty input → empty output)", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("a single live cell at (0,0) dies (0 neighbors) → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("Rule 1 - Underpopulation: two adjacent cells [(0,1), (1,1)] both die (1 neighbor each) → []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("Rule 4 - Reproduction: dead cell with exactly 3 live neighbors becomes alive — [(0,2), (1,2), (0,1)] produces (1,1) among the live cells of next gen", () => {
18	    expect(nextGeneration([[0, 2], [1, 2], [0, 1]])).toContainEqual([1, 1]);
19	  });
20	
21	  it("Rule 2 - Survival: center cell (1,1) with 3 live neighbors [(0,2),(1,2),(2,2)] survives in the next generation", () => {
22	    expect(nextGeneration([[1, 1], [0, 2], [1, 2], [2, 2]])).toContainEqual([1, 1]);
23	  });
24	
